const wrapped = $input.first().json;
const body = wrapped.body && typeof wrapped.body === 'object' && !Array.isArray(wrapped.body) ? wrapped.body : wrapped;

const event = {
  ...wrapped,
  ...body,
  type: body.type ?? wrapped.type ?? 'unknown',
  societyId: body.societyId ?? wrapped.societyId ?? null,
  societyName: body.societyName ?? wrapped.societyName ?? 'Society',
  summary: body.summary ?? wrapped.summary ?? '',
  title: body.title ?? body.metadata?.title ?? null,
  body: body.body ?? body.metadata?.body ?? null,
  message_body: body.message_body ?? body.messageBody ?? body.message ?? wrapped.message_body ?? wrapped.message ?? '',
  sender_whatsapp: body.sender_whatsapp ?? body.senderWhatsapp ?? wrapped.sender_whatsapp ?? null,
  receiver_whatsapp: body.receiver_whatsapp ?? body.receiverWhatsapp ?? body.to ?? wrapped.receiver_whatsapp ?? null,
  metadata: body.metadata ?? wrapped.metadata ?? {}
};

function sanitizeMessageText(raw) {
  let text = String(raw ?? '').trim();
  while (text.startsWith('==')) text = text.slice(2).trim();
  while (text.startsWith('=')) text = text.slice(1).trim();
  text = text.replace(/\{\{[^}]+\}\}/g, '').trim();
  return text;
}

function resolveRouteCategory(type) {
  const t = String(type ?? '').toLowerCase();
  if (t.startsWith('notice')) return 'notice';
  if (t.startsWith('visitor')) return 'visitor';
  if (t.startsWith('payment')) return 'payment';
  return 'fallback';
}

function buildWhatsAppMessage(evt) {
  const prebuilt = sanitizeMessageText(evt.message_body);
  if (prebuilt) return prebuilt;
  const societyName = evt.societyName ?? 'Society';
  const type = String(evt.type ?? '');
  if (type.startsWith('notice')) {
    const title = evt.title ?? evt.summary ?? 'New notice';
    const noticeBody = evt.body ?? '';
    return `📢 *${societyName}*\n\n${title}\n\n${noticeBody}\n\n_View in Syncra Society portal_`;
  }
  if (type.startsWith('visitor')) {
    return `🚪 *${societyName}*\n\n${evt.summary ?? 'Visitor approval request'}\n\nApprove or deny from your resident app.`;
  }
  if (type.startsWith('payment')) {
    return `💳 *${societyName}*\n\n${evt.summary ?? 'Payment update'}\n\n_View in Syncra Society portal_`;
  }
  if (type === 'auth.email_verification') {
    const code = evt.metadata?.code ?? evt.code ?? '';
    const verifyUrl = evt.metadata?.verifyUrl ?? '';
    return `*Syncra Society*\n\nYour verification code: ${code}\n\nOr verify here: ${verifyUrl}`;
  }
  return `*${societyName}*\n\n${evt.summary ?? 'Portal update'}\n\n_View in Syncra Society portal_`;
}

const routeCategory = resolveRouteCategory(event.type);
const whatsappMessage = buildWhatsAppMessage(event);
const toPhone = event.receiver_whatsapp ?? null;

return [{ json: { ...event, routeCategory, whatsappMessage, toPhone, sendCount: 1 } }];

const item = $input.first().json;
const meta = item.metadata ?? {};
const amount = meta.amount ?? item.amount ?? null;
const suffix = amount ? ` Amount: ₹${amount}` : '';
const msg = String(item.whatsappMessage ?? item.summary ?? 'Payment reminder') + suffix;
return [{ json: { ...item, channel: 'payment', whatsappMessage: msg } }];

const wrapped = $input.first().json;
const body = wrapped.body && typeof wrapped.body === 'object' && !Array.isArray(wrapped.body) ? wrapped.body : wrapped;
const merged = { ...wrapped, ...body };
const description = merged.description ?? merged.text ?? merged.Body ?? merged.body?.Body ?? merged.body?.text ?? '';
return [{ json: { societyId: merged.societyId ?? merged.society_id ?? null, flatNumber: merged.flatNumber ?? merged.flat_number ?? null, phone: merged.phone ?? merged.From ?? merged.from ?? null, messageType: merged.messageType ?? merged.message_type ?? 'ticket', subject: merged.subject ?? merged.Subject ?? null, description: String(description ?? '').trim(), amount: merged.amount ?? null, body: merged.body ?? body } }];

const item = $input.first().json;
const phone = String(item.phone ?? item.From ?? 'whatsapp-unknown').trim();
const flatNumber = item.flatNumber ? String(item.flatNumber).trim() : null;
return [{ json: { ...item, portalPayload: { societyId: item.societyId, flatNumber, phone, messageType: item.messageType ?? 'ticket', subject: item.subject?.trim() || (flatNumber ? `WhatsApp helpdesk — Flat ${flatNumber}` : 'WhatsApp helpdesk ticket'), description: String(item.description ?? '').trim(), amount: item.amount ?? null } } }];

const item = $input.first();
let twiml = String(item.body ?? item.json ?? '').trim();
if (!twiml.includes('<Response>')) {
  let msg = twiml;
  while (msg.startsWith('==')) msg = msg.slice(2).trim();
  while (msg.startsWith('=')) msg = msg.slice(1).trim();
  msg = msg.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  twiml = `<?xml version="1.0" encoding="UTF-8"?><Response><Message>${msg}</Message></Response>`;
} else {
  twiml = twiml.replace(/==+/g, '');
  const match = twiml.match(/<Message>([\s\S]*?)<\/Message>/i);
  if (match) {
    let inner = match[1].trim();
    while (inner.startsWith('=')) inner = inner.slice(1).trim();
    twiml = `<?xml version="1.0" encoding="UTF-8"?><Response><Message>${inner}</Message></Response>`;
  }
}
return [{ json: { twiml } }];
